import React, { useEffect, useRef } from 'react';

function DottedSphere({ size = 600, className = '' }) {
  const canvasRef = useRef(null);
  const animationRef = useRef(null);
  const angleRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const dpr = window.devicePixelRatio || 1;

    canvas.width = size * dpr;
    canvas.height = size * dpr;
    ctx.scale(dpr, dpr);

    const centerX = size / 2;
    const centerY = size / 2;

    function draw() {
      ctx.clearRect(0, 0, size, size);

      // Background glow
      const glow = ctx.createRadialGradient(centerX, centerY, 0, centerX, centerY, size / 2);
      glow.addColorStop(0, 'rgba(99, 102, 241, 0.12)');
      glow.addColorStop(0.5, 'rgba(139, 92, 246, 0.06)');
      glow.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, size, size);

      const dots = [];
      const rotation = angleRef.current;
      const numRings = 16;
      const tiltX = 0.75; // Nghiêng theo trục X

      // Tạo các vòng elip lồng nhau
      for (let ring = 1; ring <= numRings; ring++) {
        const ringRadius = (ring / numRings) * (size / 2.2);
        const numDots = Math.floor(ring * 5) + 12;

        for (let i = 0; i < numDots; i++) {
          const angle = (i / numDots) * Math.PI * 2 + rotation + (ring * 0.1);

          // Vị trí trên vòng tròn
          const x = Math.cos(angle) * ringRadius;
          const y = Math.sin(angle) * ringRadius * tiltX; // Nghiêng
          const z = Math.sin(angle) * ringRadius * 0.5; // Depth

          dots.push({
            x: centerX + x,
            y: centerY + y,
            z: z,
            depth: (z + size / 2) / size,
            ring: ring
          });
        }
      }

      // Sort back to front
      dots.sort((a, b) => a.z - b.z);

      // Draw dots
      dots.forEach(dot => {
        const alpha = 0.15 + dot.depth * 0.6;
        const dotSize = 1 + dot.depth * 2;

        // Glow
        if (dot.depth > 0.5) {
          ctx.beginPath();
          ctx.arc(dot.x, dot.y, dotSize * 3, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(139, 92, 246, ${alpha * 0.1})`;
          ctx.fill();
        }

        ctx.beginPath();
        ctx.arc(dot.x, dot.y, dotSize, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(167, 139, 250, ${alpha})`;
        ctx.fill();
      });

      angleRef.current += 0.002;
      animationRef.current = requestAnimationFrame(draw);
    }

    draw();

    return () => {
      if (animationRef.current) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, [size]);

  return (
    <div className={`absolute pointer-events-none ${className}`}>
      <canvas 
        ref={canvasRef}
        style={{ width: size, height: size }}
      />
    </div>
  );
}

export default DottedSphere;
